drlScheduler.SubbandSize         = 4;
drlScheduler.DRLDebug            = false;

% HARQ management
drlScheduler.MinFreeHARQForNewTx     = 1;
drlScheduler.MaxDLHARQBusyTTI        = 30;
drlScheduler.HARQReleaseDebug        = false;
drlScheduler.MaxDLReTxOccupancyRatio = 0.6;

% Pairing constraints: DRL learns its own pairing policy — disable MATLAB filter.
