inst_tp_all = zeros(1, obj.MaxUEs);   % [Mbps], indexed by RNTI
slot_s = obj.CellConfig(1).SlotDuration * 1e-3;

% EMA alpha: mirror PFSWindowSize (default 20 slots → α = 1/20 = 0.05)
