1	%% NR Cell — 128T128R DL MU-MIMO + DRL Socket (Rel-19 eTypeII, Subband CQI)
2	% System-level MU-MIMO simulation with nrDRLScheduler connected to a Python
3	% DRL training server via TCP socket.
4	%
5	% Base: CSIRS_128T128R_v3_0_MUMIMO.m  (128T128R, eTypeII-r19, subband PMI+CQI)
6	% Added: socket API, FTP-3 traffic, allocation-map export (from CSIRS_32T32R_SOCKET.m)
7	%
8	% Observation space delivered to Python per TTI (via TTI_START JSON):
9	%   1. avg_tp       [MaxUEs]            – EMA actual DL throughput (Mbps)
10	%   2. ue_rank      [MaxUEs]            – RI per UE
11	%   3. occupied_rbgs / allocMatrix      – per-layer RBG allocation (tracked by Python)
12	%   4. buf          [MaxUEs]            – DL buffer status (bytes)
13	%   5. curr_mcs     [MaxUEs]            – effective MCS after OLLA
14	%   6. ue_i1        [MaxUEs x 2]        – eTypeII beam-group index i1
15	%   7. sub_cqi      [MaxUEs x numRBGs]  – subband CQI (resampled to RBG grid)
16	%   8. max_cross_corr [MaxUEs x MaxUEs x numRBGs] – max-column kappa, NOT MATLAB built-in
17	%
18	% Author: ThangTQ23 — VSI, 2026-04
19	
20	%% ====================== 1. PATH SETUP & LOGGING ======================
21	% Prepend patched wirelessnetwork + 5g libraries so that:
22	%   • nrGNB supports NumTransmitAntennas = 128
23	%   • eTypeII-r19 codebook path is activated in nrNodeValidation / nrUEAbstractPHY
24	clear classes; rehash; close all;
25	
26	projectRoot = fileparts(mfilename('fullpath'));
27	addpath(genpath(fullfile(projectRoot, 'wirelessnetwork')), '-begin');
28	addpath(genpath(fullfile(projectRoot, '5g')),              '-begin');
29	
30	wirelessnetworkSupportPackageCheck
31	
32	% Diary log (timestamped, written to logs_v4/)
33	logDir  = fullfile(projectRoot, 'logs_v4');
34	if exist(logDir, 'dir'), rmdir(logDir, 's'); end
35	mkdir(logDir);
36	logFile = fullfile(logDir, 'matlab_log_' + string(datetime('now', 'Format', 'yyyyMMdd_HHmmss')) + '.txt');
37	diary(logFile);
38	
39	%% ====================== 2. SIMULATION PARAMETERS ======================
40	
41	% ── PMI/CQI reporting mode ───────────────────────────────────────────────
42	% 'Subband': per-subband precoder (PMI) + per-subband CQI.
43	%   With NRB=24 @ 30 kHz → subband size = 4 RBs → numSubbands = 6
44	%   (TS 38.214 Table 5.2.1.4-2, NRB ∈ [24, 72])
45	% 'Wideband': single precoder + single CQI — faster, less accurate.
46	pmiCQIMode = "Subband";   % change to "Wideband" for faster debug runs
47	
48	rng("default");
49	numFrameSimulation = 5;
50	networkSimulator   = wirelessNetworkSimulator.init;
51	
52	%% ====================== 3. gNB CONFIGURATION (128T128R) ======================
53	% 128T128R, TDD, n79 4.9 GHz, 10 MHz / 30 kHz SCS.
54	% Use channelBW = 100e6 / numRB = 273 for production — 10 MHz here for speed.
55	
56	gNBPosition  = [0 0 30];      % [x y z] metres
57	duplexMode   = "TDD";
58	
59	carrierFreq  = 4.9e9;         % n79 centre frequency (Hz)
60	channelBW    = 10e6;          % channel bandwidth — change to 100e6 for production
61	scs          = 30e3;          % subcarrier spacing (Hz)
62	% TS 38.104 Table 5.3.2-1 (FR1, 30 kHz SCS):
63	%   5→11  10→24  15→38  20→51  40→106  100→273
64	numRB = 24;                   % matches 10 MHz @ 30 kHz SCS
65	
66	gNB = nrGNB( ...
67	    Position             = gNBPosition, ...
68	    TransmitPower        = 40, ...
69	    CarrierFrequency     = carrierFreq, ...
70	    ChannelBandwidth     = channelBW, ...
71	    SubcarrierSpacing    = scs, ...
72	    NumResourceBlocks    = numRB, ...
73	    NumTransmitAntennas  = 128, ...
74	    NumReceiveAntennas   = 128, ...
75	    DuplexMode           = duplexMode, ...
76	    ReceiveGain          = 11, ...
77	    SRSPeriodicityUE     = 20);
78	
79	fprintf('gNB: 128T128R | %.1f GHz (n79) | %s | BW=%.0f MHz | NRB=%d\n', ...
80	    carrierFreq/1e9, duplexMode, channelBW/1e6, numRB);
81	
82	% ── PMI/CQI mode must be set BEFORE connectUE ────────────────────────────
83	% nrNodeValidation picks this up during connectUE to configure the UE's
84	% abstract-PHY CSI report (subband vs wideband CQI vector in csi.CQI).
85	gNB.PMICQIMode = pmiCQIMode;
86	
87	%% ====================== 4. DRL SCHEDULER CONFIGURATION ======================
88	
89	numUEs = 16;   % total UEs in this simulation
90	
91	% ── MU-MIMO pairing constraints ──────────────────────────────────────────
92	% eTypeII DOF constraint: L=2 beams × 2 polarisations = 4D subspace.
93	% K×r ≤ 4 → with rank=2 and K=2 UEs: 4 streams in 4D → orthogonal planes.
94	muMIMOConfig = struct( ...
95	    MaxNumUsersPaired    = 4, ...   % ≤ 2 recommended for rank-2 UEs
96	    MaxNumLayers         = 4, ...
97	    MinNumRBs            = 2, ...
98	    SemiOrthogonalityFactor = 0.7, ...
99	    MinCQI               = 1);
100	
101	% ── OLLA ─────────────────────────────────────────────────────────────────
102	% TargetBLER = StepDown / (StepDown + StepUp) = 0.03/0.30 = 10%
103	% MCSOffset accumulates via HARQ ACK/NACK (no reset — State 3).
104	% SU-measured CQI overestimates MU-MIMO SINR → OLLA must converge first.
105	ollaConfig = struct('InitialOffset', 0, 'StepUp', 0.27, 'StepDown', 0.03);
106	
107	% ── nrDRLScheduler ───────────────────────────────────────────────────────
108	drlScheduler = nrDRLScheduler();
109	drlScheduler.EnableDRL           = true;
110	drlScheduler.TrainingMode        = true;   % TTI_START / LAYER_ACT / TTI_DONE protocol
111	drlScheduler.NumLayers           = muMIMOConfig.MaxNumLayers;
112	drlScheduler.MaxUsersPerRBG      = muMIMOConfig.MaxNumUsersPaired;
113	drlScheduler.MaxUEs              = numUEs;
114	% SubbandSize: 3GPP subband size for CQI (informational — scheduler uses numRBGs internally)
115	% NRB=24 → subband size = 4 RBs (TS 38.214 Table 5.2.1.4-2)
116	drlScheduler.SubbandSize         = 4;
117	drlScheduler.DRLDebug            = false;
118	
119	% Pairing constraints: DRL learns its own pairing policy — disable MATLAB filter.
120	% Set true to let MATLAB enforce i1-match + precoder orthogonality as a hard gate.
121	drlScheduler.EnablePairingConstraints = false;
122	drlScheduler.SemiOrthogonalityFactor  = muMIMOConfig.SemiOrthogonalityFactor;
123	drlScheduler.MU_MCSBackoff            = 0;
124	
125	% Throughput EMA normalisation (Mbps) — scales fR feature to [0,1]
126	drlScheduler.MaxTput = 100.0;
127	
128	% ── Connect to Python DRL server ─────────────────────────────────────────
129	ok = drlScheduler.connectToDRLAgent('127.0.0.1', 6666);
130	assert(ok, '[v4] Cannot connect to DRL server. Start Python train script first.');
131	
132	% ── configureScheduler ───────────────────────────────────────────────────
133	configureScheduler(gNB, ...
134	    'Scheduler',               drlScheduler, ...
135	    'ResourceAllocationType',  0, ...          % RAT-0 (RBG bitmap)
136	    'MaxNumUsersPerTTI',       numUEs, ...
137	    'PFSWindowSize',           20, ...         % EMA window for PF throughput tracking
138	    'MUMIMOConfigDL',          muMIMOConfig, ...
139	    'LinkAdaptationConfigDL',  ollaConfig, ...
140	    'CSIMeasurementSignalDL',  "CSI-RS", ...
141	    'RVSequence',              0);             % RV=0 only (no HARQ retransmissions)
142	% NOTE: SchedulerStrategy=1 omitted — it triggers nrUEContext.updateUEsServedDataRate
143	% in MU-MIMO mode → crash "Matrix dimensions must agree".  EMA tracking is handled
144	% entirely inside nrDRLScheduler.ActualTputEMA.
145	
146	%% ====================== 5. UE DEPLOYMENT ======================
147	% 16 UEs in a 120° sector, r ∈ [50, 500] m (uniform on area via sqrt-trick).
148	% 4Tx/4Rx per UE: needed for rank > 1 with eTypeII precoding.
149	
150	ueNumTx = 2;
151	ueNumRx = 4;
152	
153	rMin = 50;  rMax = 500;
154	rng(42);
155	azDeg = -60 + 120 .* rand(numUEs, 1);
156	rDist = sqrt(rMin^2 + (rMax^2 - rMin^2) .* rand(numUEs, 1));
157	[xPos, yPos, zPos] = sph2cart(deg2rad(azDeg), zeros(numUEs,1), rDist);
158	uePositions = [xPos, yPos, zPos] + gNBPosition;
159	
160	noiseFigMin = 7;  noiseFigMax = 9;
161	UEs = nrUE.empty(0, numUEs);
162	for i = 1:numUEs
163	    nf = noiseFigMin + (noiseFigMax - noiseFigMin) * rand();
164	    UEs(i) = nrUE( ...
165	        Name                = "UE-" + i, ...
166	        Position            = uePositions(i,:), ...
167	        NumTransmitAntennas = ueNumTx, ...
168	        NumReceiveAntennas  = ueNumRx, ...
169	        ReceiveGain         = 0, ...
170	        NoiseFigure         = nf);
171	end
172	fprintf('UE distances (m): %s\n', mat2str(round(rDist), 1));
173	
174	% ── Traffic: FTP Model 3 (always-on 6 Mbps / 1.5 kB packets) ────────────
175	% Full-buffer DL is unrealistic for DRL reward — FTP3 gives finite buffer
176	% so buffer feature (obs #4) has meaningful variation.
177	connectUE(gNB, UEs, FullBufferTraffic = "off", CSIReportPeriodicity = 10);
178	for i = 1:numUEs
179	    src             = networkTrafficOnOff;
180	    src.PacketSize  = 1500;   % bytes
181	    src.DataRate    = 6e6;    % bps (= 1500 × 8 × 500 pkt/s)
182	    src.OnTime      = 1e9;    % always ON
183	    src.OffTime     = 0;
184	    addTrafficSource(gNB, src, 'DestinationNode', UEs(i));
185	end
186	
187	% Give UE handles to DRL scheduler so it can read MAC.ReceivedBytes per TTI
188	drlScheduler.UEList = UEs;
189	
190	%% ====================== 6. NETWORK SIMULATOR NODES ======================
191	
192	addNodes(networkSimulator, gNB);
193	addNodes(networkSimulator, UEs);
194	
195	%% ====================== 7. CHANNEL MODEL (CDL-D) ======================
196	% CDL-D: strong LoS, DS=100 ns, Doppler=5 Hz — rank-friendly for eTypeII.
197	
198	channelConfig = struct( ...
199	    DelayProfile        = "CDL-D", ...
200	    DelaySpread         = 100e-9, ...
201	    MaximumDopplerShift = 5);
202	
203	channels          = hNRCreateCDLChannels(channelConfig, gNB, UEs);
204	customChannelModel = hNRCustomChannelModel(channels);
205	addChannelModel(networkSimulator, @customChannelModel.applyChannelModel);
206	
207	%% ====================== 8. LOGGING & VISUALISATION ======================
208	
209	enableTraces = true;
210	if enableTraces
211	    simSchedulingLogger = helperNRSchedulingLogger(numFrameSimulation, gNB, UEs);
212	    simPhyLogger        = helperNRPhyLogger(numFrameSimulation, gNB, UEs);
213	end
214	
215	metricsVisualizer = helperNRMetricsVisualizer(gNB, UEs, ...
216	    'RefreshRate',         1000, ...
217	    'PlotSchedulerMetrics', true, ...
218	    'PlotPhyMetrics',      false, ...
219	    'PlotCDFMetrics',      true, ...
220	    'LinkDirection',       0);
221	
222	%% ====================== 9. SIMULATION CONDITIONS SUMMARY ======================
223	
224	slotsPerSubfm = scs / 15e3;
225	slotDurMs     = 1 / slotsPerSubfm;
226	slotsPerFrm   = 10 * slotsPerSubfm;
227	csiPeriodicity = 10;
228	numCSIEvents  = floor(numFrameSimulation * slotsPerFrm / csiPeriodicity);
229	
230	if strcmpi(pmiCQIMode, 'Subband')
231	    if numRB >= 145; sbSize = 16; elseif numRB >= 73; sbSize = 8; else; sbSize = 4; end
232	    numSubbands = ceil(numRB / sbSize);
233	    modeStr = sprintf('Subband | %d subbands × %d RBs', numSubbands, sbSize);
234	else
235	    numSubbands = 1; sbSize = numRB;
236	    modeStr = 'Wideband';
237	end
238	
239	sep = repmat('═', 1, 72);
240	fprintf('\n%s\n', sep);
241	fprintf('  SIMULATION CONDITIONS — 128T128R MU-MIMO DL + DRL Socket (v4.0)\n');
242	fprintf('%s\n', sep);
243	fprintf('  gNB      : 128T/128R | %.1f GHz (n79) | %s | BW=%.0f MHz | NRB=%d\n', ...
244	    carrierFreq/1e9, duplexMode, channelBW/1e6, numRB);
245	fprintf('             SCS=%.0f kHz | Tx=60 dBm | Rx Gain=11 dB\n', scs/1e3);
246	fprintf('  UEs      : %d | %dTx/%dRx | r∈[%d,%d] m | NF∈[%d,%d] dB\n', ...
247	    numUEs, ueNumTx, ueNumRx, rMin, rMax, noiseFigMin, noiseFigMax);
248	fprintf('  Channel  : %s | DS=%.0f ns | fD=%.0f Hz\n', ...
249	    channelConfig.DelayProfile, channelConfig.DelaySpread*1e9, channelConfig.MaximumDopplerShift);
250	fprintf('  Scheduler: CSI-RS | MU-MIMO ≤%d paired / ≤%d layers | RAT-0\n', ...
251	    muMIMOConfig.MaxNumUsersPaired, muMIMOConfig.MaxNumLayers);
252	fprintf('             OLLA: init=%g up=%.2f down=%.2f → target BLER~%.0f%%\n', ...
253	    ollaConfig.InitialOffset, ollaConfig.StepUp, ollaConfig.StepDown, ...
254	    100*ollaConfig.StepDown/(ollaConfig.StepDown+ollaConfig.StepUp));
255	fprintf('  CSI      : eTypeII-r19 | Panel [1×16×4] | L=2 beams | %s\n', modeStr);
256	fprintf('             Period=%d slots (%.1f ms) → ~%d reports/UE in %d frames\n', ...
257	    csiPeriodicity, csiPeriodicity*slotDurMs, numCSIEvents, numFrameSimulation);
258	fprintf('  DRL      : Socket 127.0.0.1:6666 | TrainingMode=ON | Layers=%d\n', ...
259	    drlScheduler.NumLayers);
260	fprintf('  Traffic  : FTP Model 3 | 1500 B pkts | 6 Mbps/UE\n');
261	fprintf('  Sim      : %d frames | %.0f ms\n', numFrameSimulation, numFrameSimulation*10);
262	fprintf('%s\n\n', sep);
263	
264	%% ====================== 10. RUN SIMULATION ======================
265	
266	simulationTime = numFrameSimulation * 1e-2;   % seconds
267	fprintf('Running simulation (%.0f ms)...\n', simulationTime * 1e3);
268	run(networkSimulator, simulationTime);
269	
270	% Notify Python that episode is complete
271	drlScheduler.drlSendJSON(struct('type', 'STOP'));
272	fprintf('Sent STOP to Python DRL server.\n');
273	
274	%% ====================== 11. KPI SUMMARY & LOGS ======================
275	
276	displayPerformanceIndicators(metricsVisualizer);
277	
278	if enableTraces
279	    % ── Collect logs ─────────────────────────────────────────────────────
280	    if gNB.DuplexMode == "FDD"
281	        logInfo = struct('DLTimeStepLogs',[], 'ULTimeStepLogs',[], ...
282	                         'SchedulingAssignmentLogs',[], 'PhyReceptionLogs',[]);
283	        [logInfo.DLTimeStepLogs, logInfo.ULTimeStepLogs] = getSchedulingLogs(simSchedulingLogger);
284	    else
285	        logInfo = struct('TimeStepLogs',[], 'SchedulingAssignmentLogs',[], 'PhyReceptionLogs',[]);
286	        logInfo.TimeStepLogs = getSchedulingLogs(simSchedulingLogger);
287	    end
288	    logInfo.SchedulingAssignmentLogs = getGrantLogs(simSchedulingLogger);
289	    logInfo.PhyReceptionLogs         = getReceptionLogs(simPhyLogger);
290	    save(fullfile(logDir, 'simulationLogs.mat'), 'logInfo');
291	    save('logInfo.mat', 'logInfo');
292	
293	    % ── Per-UE Grant/MCS Summary ─────────────────────────────────────────
294	    colMap   = simSchedulingLogger.GrantLogsColumnIndexMap;
295	    grantRaw = logInfo.SchedulingAssignmentLogs(2:end, :);
296	    rntiCol  = colMap('RNTI');
297	    mcsCol   = colMap('MCS Index');
298	    lyrCol   = colMap('NumLayers');
299	    typeCol  = colMap('Grant Type');
300	    isDL     = strcmp(grantRaw(:, typeCol), 'DL');
301	    dlData   = grantRaw(isDL, :);
302	
303	    sep2 = repmat('─', 1, 72);
304	    fprintf('\n%s\n', sep2);
305	    fprintf('  gNB DL Grant Summary  (%d grants | %d frames | %s)\n', ...
306	        sum(isDL), numFrameSimulation, pmiCQIMode);
307	    fprintf('%s\n', sep2);
308	    fprintf('  %-6s  %7s  %8s  %8s  %8s  %8s\n', ...
309	        'UE', 'Grants', 'MCS avg', 'MCS min', 'MCS max', 'Lyr avg');
310	    fprintf('%s\n', sep2);
311	    for ueIdx = 1:numUEs
312	        mask = cell2mat(dlData(:, rntiCol)) == ueIdx;
313	        if ~any(mask), continue; end
314	        mcsV = cell2mat(dlData(mask, mcsCol));
315	        lyrV = cell2mat(dlData(mask, lyrCol));
316	        fprintf('  UE-%-3d  %7d  %8.1f  %8d  %8d  %8.1f\n', ...
317	            ueIdx, sum(mask), mean(mcsV), min(mcsV), max(mcsV), mean(lyrV));
318	    end
319	    fprintf('%s\n\n', sep2);
320	
321	    % ── Export allocation maps ────────────────────────────────────────────
322	    allocMapDir = fullfile(logDir, 'allocation_maps');
323	    ttiBySlot = [];
324	    if isprop(drlScheduler, 'TrainingTTISlotIndex') && ~isempty(drlScheduler.TrainingTTISlotIndex)
325	        maxSlot   = max(drlScheduler.TrainingTTISlotIndex);
326	        ttiBySlot = -1 * ones(maxSlot + 1, 1);
327	        for tIdx = 1:numel(drlScheduler.TrainingTTISlotIndex)
328	            sl = drlScheduler.TrainingTTISlotIndex(tIdx);
329	            if sl >= 0, ttiBySlot(sl + 1) = tIdx - 1; end
330	        end
331	    end
332	    numMaps = exportDLAllocationMaps(logInfo, duplexMode, 0, ...
333	        muMIMOConfig.MaxNumLayers, allocMapDir, ttiBySlot);
334	    fprintf('Saved %d DL allocation maps to %s\n', numMaps, allocMapDir);
335	end
336	
337	%% ====================== 12. OLLA CONVERGENCE MONITOR ======================
338	
339	if enableTraces
340	    rxLogs   = logInfo.PhyReceptionLogs;
341	    rxColMap = simPhyLogger.ColumnIndexMap;
342	    frameCol = rxColMap('Frame');
343	    failCol  = rxColMap('Number of Decode Failures(DL)');
344	    pktCol   = rxColMap('Number of Packets(DL)');
345	    rxData   = rxLogs(2:end, :);
346	    rxFrames = cell2mat(rxData(:, frameCol));
347	
348	    blerPerFrame = zeros(numFrameSimulation, 1);
349	    for f = 0:numFrameSimulation-1
350	        fMask = rxFrames == f;
351	        if ~any(fMask), continue; end
352	        fails = sum(cellfun(@sum, rxData(fMask, failCol)));
353	        pkts  = sum(cellfun(@sum, rxData(fMask, pktCol)));
354	        if pkts > 0, blerPerFrame(f+1) = fails / pkts; end
355	    end
356	
357	    frameColG   = colMap('Frame');
358	    mcsPerFrame = zeros(numFrameSimulation, 1);
359	    dlFrames    = cell2mat(dlData(:, frameColG));
360	    for f = 0:numFrameSimulation-1
361	        fMask = dlFrames == f;
362	        if ~any(fMask), continue; end
363	        mcsPerFrame(f+1) = mean(cell2mat(dlData(fMask, mcsCol)));
364	    end
365	
366	    frames = (1:numFrameSimulation)';
367	    figure('Name', 'OLLA Convergence Monitor — v4.0');
368	    tiledlayout(2, 1, TileSpacing='compact');
369	
370	    nexttile;
371	    plot(frames, blerPerFrame * 100, 'b-o', MarkerSize=4, LineWidth=1.2);
372	    yline(10, 'r--', 'Target 10%', LabelHorizontalAlignment='left');
373	    xlabel('Frame'); ylabel('BLER (%)'); title('Per-Frame DL BLER');
374	    grid on; ylim([0 100]);
375	
376	    nexttile;
377	    plot(frames, mcsPerFrame, 'm-o', MarkerSize=4, LineWidth=1.2);
378	    xlabel('Frame'); ylabel('MCS avg');
379	    title('Per-Frame DL MCS Average (OLLA accumulating)');
380	    grid on; ylim([0 28]);
381	
382	    fprintf('\n  BLER range : %.1f%% – %.1f%%  (first 5 avg: %.1f%%  |  last 5 avg: %.1f%%)\n', ...
383	        min(blerPerFrame)*100, max(blerPerFrame)*100, ...
384	        mean(blerPerFrame(1:min(5,end)))*100, ...
385	        mean(blerPerFrame(max(1,end-4):end))*100);
386	    fprintf('  MCS  range : %.1f – %.1f  (first 5 avg: %.1f  |  last 5 avg: %.1f)\n\n', ...
387	        min(mcsPerFrame), max(mcsPerFrame), ...
388	        mean(mcsPerFrame(1:min(5,end))), ...
389	        mean(mcsPerFrame(max(1,end-4):end)));
390	end
391	
392	%% ====================== 13. MU-MIMO PAIRING ANALYSIS ======================
393	
394	if enableTraces
395	    avgUEsPerRB = calculateAvgUEsPerRBDL(logInfo, gNB.NumResourceBlocks, 0, duplexMode);
396	    figure('Name', 'MU-MIMO Pairing — v4.0');
397	    histogram(avgUEsPerRB, BinWidth=0.1);
398	    title('Distribution of Avg UEs per RB (128T128R, DRL Scheduler)');
399	    xlabel('Avg UEs per RB'); ylabel('Occurrences'); grid on;
400	
401	    [pairingCounts, ~] = calculateUEPairingStats(logInfo, gNB.NumResourceBlocks, 0, duplexMode);
402	    figure('Name', 'UE Pairing Distribution — v4.0');
403	    bar(pairingCounts(:,1), pairingCounts(:,2));
404	    title('UE Pairing Distribution per RBG'); xlabel('UEs per RBG'); ylabel('Count');
405	    xticks(0:max(pairingCounts(:,1))); grid on;
406	
407	    fprintf('\n=== UE PAIRING STATISTICS ===\n');
408	    totalRBGSlots = sum(pairingCounts(:,2));
409	    for i = 1:size(pairingCounts, 1)
410	        n = pairingCounts(i,1); c = pairingCounts(i,2);
411	        pct = 100 * c / totalRBGSlots;
412	        if     n == 0, fprintf('  Empty    : %d (%.1f%%)\n', c, pct);
413	        elseif n == 1, fprintf('  SU-MIMO  : %d (%.1f%%)\n', c, pct);
414	        else,          fprintf('  %d-user MU: %d (%.1f%%)\n', n, c, pct);
415	        end
416	    end
417	end
418	
419	diary('off');
420	
421	%% ====================== HELPER FUNCTIONS ======================
422	
423	% ── calculateAvgUEsPerRBDL ───────────────────────────────────────────────
424	function avgUEsPerRB = calculateAvgUEsPerRBDL(logInfo, numResourceBlocks, ratType, duplexMode)
425	    if strcmp(duplexMode, 'TDD')
426	        timeStepLogs    = logInfo.TimeStepLogs;
427	        freqAllocations = timeStepLogs(:, 5);
428	    else
429	        timeStepLogs    = logInfo.DLTimeStepLogs;
430	        freqAllocations = timeStepLogs(:, 4);
431	    end
432	    numOfSlots = size(timeStepLogs, 1) - 1;
433	    if ~ratType
434	        numRBG       = size(freqAllocations{2}, 2);
435	        P            = ceil(numResourceBlocks / numRBG);
436	        numRBsPerRBG = P * ones(1, numRBG);
437	        if mod(numResourceBlocks, P) > 0, numRBsPerRBG(end) = mod(numResourceBlocks, P); end
438	    end
439	    avgUEsPerRB = zeros(1, numOfSlots);
440	    for slotIdx = 1:numOfSlots
441	        if strcmp(duplexMode, 'TDD')
442	            if ~strcmp(timeStepLogs{slotIdx+1, 4}, 'DL'), continue; end
443	        end
444	        freqAlloc = freqAllocations{slotIdx + 1};
445	        if ~ratType
446	            total = sum(arrayfun(@(rbg) nnz(freqAlloc(:,rbg) > 0) * numRBsPerRBG(rbg), 1:numRBG));
447	            avgUEsPerRB(slotIdx) = total / numResourceBlocks;
448	        else
449	            usage = zeros(1, numResourceBlocks);
450	            for u = 1:size(freqAlloc, 1)
451	                usage(freqAlloc(u,1)+1 : freqAlloc(u,1)+freqAlloc(u,2)) = ...
452	                    usage(freqAlloc(u,1)+1 : freqAlloc(u,1)+freqAlloc(u,2)) + 1;
453	            end
454	            avgUEsPerRB(slotIdx) = mean(usage(usage > 0));
455	        end
456	    end
457	    avgUEsPerRB = avgUEsPerRB(avgUEsPerRB > 0);
458	end
459	
460	% ── calculateUEPairingStats ───────────────────────────────────────────────
461	function [pairingCounts, pairingDistribution] = calculateUEPairingStats( ...
462	        logInfo, numResourceBlocks, ratType, duplexMode)
463	    if strcmp(duplexMode, 'TDD')
464	        timeStepLogs    = logInfo.TimeStepLogs;
465	        freqAllocations = timeStepLogs(:, 5);
466	    else
467	        timeStepLogs    = logInfo.DLTimeStepLogs;
468	        freqAllocations = timeStepLogs(:, 4);
469	    end
470	    numOfSlots  = size(timeStepLogs, 1) - 1;
471	    numRBG      = size(freqAllocations{2}, 2);
472	    pairingMap  = zeros(1, 17);   % indices: 0..16 UEs
473	    pairingDistribution = cell(numOfSlots, 1);
474	    for slotIdx = 1:numOfSlots
475	        if strcmp(duplexMode, 'TDD')
476	            if ~strcmp(timeStepLogs{slotIdx+1, 4}, 'DL'), continue; end
477	        end
478	        freqAlloc = freqAllocations{slotIdx + 1};
479	        if ~ratType
480	            for rbgIdx = 1:numRBG
481	                n = nnz(freqAlloc(:, rbgIdx) > 0);
482	                pairingMap(n + 1) = pairingMap(n + 1) + 1;
483	            end
484	        else
485	            usage = zeros(1, numResourceBlocks);
486	            for u = 1:size(freqAlloc, 1)
487	                s = freqAlloc(u,1); l = freqAlloc(u,2);
488	                if l > 0, usage(s+1:s+l) = usage(s+1:s+l) + 1; end
489	            end
490	            for rb = 1:numResourceBlocks
491	                n = usage(rb);
492	                pairingMap(n + 1) = pairingMap(n + 1) + 1;
493	            end
494	        end
495	        pairingDistribution{slotIdx} = [];
496	    end
497	    validIdx    = find(pairingMap > 0);
498	    pairingCounts = [(validIdx - 1)', pairingMap(validIdx)'];
499	end
500	
501	% ── exportDLAllocationMaps ────────────────────────────────────────────────
502	function numSaved = exportDLAllocationMaps(logInfo, duplexMode, ratType, ...
503	        maxNumLayers, outDir, ttiBySlot)
504	    numSaved = 0;
505	    if ratType ~= 0
506	        warning('exportDLAllocationMaps: RAT-0 only.'); return;
507	    end
508	    if strcmp(duplexMode, 'TDD')
509	        timeStepLogs = logInfo.TimeStepLogs;
510	        freqAllocCol = 5;  slotTypeCol = 4;
511	    else
512	        timeStepLogs = logInfo.DLTimeStepLogs;
513	        freqAllocCol = 4;  slotTypeCol = [];
514	    end
515	    if size(timeStepLogs, 1) <= 1, return; end
516	    if ~exist(outDir, 'dir'), mkdir(outDir); end
517	
518	    txTypeCol    = findLogColumn(timeStepLogs, 'Tx Type', freqAllocCol + 4);
519	    signalTypeCol = findLogColumn(timeStepLogs, 'Signal Type', -1);
520	    freqAllocations = timeStepLogs(:, freqAllocCol);
521	    numSlots = size(timeStepLogs, 1) - 1;
522	
523	    for slotIdx = 1:numSlots
524	        if signalTypeCol > 0
525	            if strcmp(timeStepLogs{slotIdx+1, signalTypeCol}, "CSIRS"), continue; end
526	        end
527	        if strcmp(duplexMode, 'TDD')
528	            st = timeStepLogs{slotIdx+1, slotTypeCol};
529	            if ~strcmp(st,'DL') && ~strcmp(st,'S'), continue; end
530	        end
531	        freqAlloc = freqAllocations{slotIdx + 1};
532	        if isempty(freqAlloc), continue; end
533	
534	        txTypePerUE = {};
535	        if txTypeCol <= size(timeStepLogs,2)
536	            txTypePerUE = timeStepLogs{slotIdx+1, txTypeCol};
537	        end
538	
539	        numRBG  = size(freqAlloc, 2);
540	        numUEs_ = size(freqAlloc, 1);
541	        allocMap = zeros(maxNumLayers, numRBG);
542	
543	        for rbgIdx = 1:numRBG
544	            sched = find(freqAlloc(:, rbgIdx) > 0);
545	            nFill = min(numel(sched), maxNumLayers);
546	            allocMap(1:nFill, rbgIdx) = sched(1:nFill);
547	        end
548	
549	        fig = figure('Visible','off');
550	        cmap = pythonLikeDiscretePalette(numUEs_);
551	        imagesc(allocMap.' + 1, [1, numUEs_+1]);
552	        axis tight; colormap(cmap);
553	        cb = colorbar; cb.Label.String = 'UE Index';
554	        cb.Ticks = 1:(numUEs_+1); cb.TickLabels = string(0:numUEs_);
555	        xlabel('Layer'); ylabel('RBG');
556	        title(sprintf('DL Alloc — slot %d', slotIdx-1));
557	        xticks(1:maxNumLayers); yticks(1:numRBG);
558	        set(gca,'YDir','normal','GridAlpha',0.35); grid on;
559	
560	        for li = 1:maxNumLayers
561	            for ri = 1:numRBG
562	                u = allocMap(li, ri);
563	                if u <= 0, continue; end
564	                txTag = normalizeTxTag(txTypePerUE, u);
565	                cellColor = cmap(u+1,:);
566	                txtColor  = ternary(sum(cellColor) > 1.7, [0 0 0], [1 1 1]);
567	                text(li, ri, {sprintf('UE%d',u), txTag}, ...
568	                    'HorizontalAlignment','center','VerticalAlignment','middle', ...
569	                    'FontSize',7,'FontWeight','bold','Color',txtColor,'Interpreter','none');
570	            end
571	        end
572	
573	        slotLinear = slotIdx - 1;
574	        ttiId = -1;
575	        if ~isempty(ttiBySlot) && (slotLinear+1) <= numel(ttiBySlot)
576	            ttiId = ttiBySlot(slotLinear + 1);
577	        end
578	        if ttiId >= 0
579	            outFile = fullfile(outDir, sprintf('dl_alloc_tti_%05d.png', ttiId));
580	        else
581	            outFile = fullfile(outDir, sprintf('dl_alloc_slot_%05d.png', slotLinear));
582	        end
583	        exportgraphics(fig, outFile, 'Resolution', 100);
584	        close(fig);
585	
586	        save(fullfile(outDir, sprintf('dl_alloc_slot_%05d.mat', slotLinear)), ...
587	            'slotLinear', 'allocMap', 'freqAlloc', 'txTypePerUE', 'ttiId');
588	        numSaved = numSaved + 1;
589	    end
590	end
591	
592	% ── findLogColumn ─────────────────────────────────────────────────────────
593	function colIdx = findLogColumn(timeStepLogs, colName, fallbackIdx)
594	    colIdx = fallbackIdx;
595	    if isempty(timeStepLogs), return; end
596	    idx = find(strcmp(timeStepLogs(1,:), colName), 1);
597	    if ~isempty(idx), colIdx = idx; end
598	end
599	
600	% ── normalizeTxTag ────────────────────────────────────────────────────────
601	function txTag = normalizeTxTag(txTypePerUE, ueIdx)
602	    txTag = 'newTx';
603	    if isempty(txTypePerUE) || ueIdx < 1 || ueIdx > numel(txTypePerUE), return; end
604	    entry = txTypePerUE{ueIdx};
605	    if iscell(entry) && ~isempty(entry), entry = entry{1}; end
606	    if isstring(entry), entry = char(entry); end
607	    if isempty(entry), return; end
608	    el = lower(string(entry));
609	    if contains(el,'retx'), txTag = 'reTx'; elseif contains(el,'newtx'), txTag = 'newTx'; else, txTag = char(entry); end
610	end
611	
612	% ── pythonLikeDiscretePalette ─────────────────────────────────────────────
613	function cmap = pythonLikeDiscretePalette(numUEs)
614	    tab20 = [31,119,180;174,199,232;255,127,14;255,187,120; ...
615	             44,160,44;152,223,138;214,39,40;255,152,150; ...
616	             148,103,189;197,176,213;140,86,75;196,156,148; ...
617	             227,119,194;247,182,210;127,127,127;199,199,199; ...
618	             188,189,34;219,219,141;23,190,207;158,218,229] / 255;
619	    cmap = zeros(numUEs + 1, 3);
620	    cmap(1,:) = [0.94 0.94 0.94];
621	    for u = 1:numUEs
622	        cmap(u+1,:) = tab20(mod(u-1, size(tab20,1)) + 1, :);
623	    end
624	end
625	
626	% ── ternary ───────────────────────────────────────────────────────────────
627	function out = ternary(cond, trueVal, falseVal)
628	    if cond, out = trueVal; else, out = falseVal; end
629	end
